import { Badge } from "@/components/ui/badge";
import { EmptyState } from "@/components/ui/empty-state";
import { formatCurrency, formatDate, formatPercent, formatSignedNumber } from "@/lib/formatters";
import type { TradeRow } from "@/lib/types";
import { truncateText } from "@/lib/utils";

function DirectionBadge({ direction }: { direction: TradeRow["direction"] }) {
  return <Badge variant={direction === "long" ? "positive" : "negative"}>{direction}</Badge>;
}

function ResultBadge({ value }: { value: number | null }) {
  return (
    <Badge variant={typeof value === "number" && value >= 0 ? "positive" : "negative"}>
      {formatPercent(value)}
    </Badge>
  );
}

export function ClosedTradesTable({
  trades,
  compact = false,
}: {
  trades: TradeRow[];
  compact?: boolean;
}) {
  if (trades.length === 0) {
    return (
      <EmptyState
        title="No closed trades"
        description="Closed trades will populate here once results are logged from posted EWC signals."
      />
    );
  }

  const visibleTrades = compact ? trades.slice(0, 6) : trades;

  return (
    <>
      <div className="grid gap-4 md:hidden">
        {visibleTrades.map((trade) => (
          <div className="rounded-3xl border border-white/10 bg-white/5 p-5" key={trade.id}>
            <div className="flex items-start justify-between gap-4">
              <div>
                <p className="text-lg font-semibold text-foreground">{trade.ticker}</p>
                <p className="mt-1 text-sm text-muted-foreground">{trade.outcome_label}</p>
              </div>
              <ResultBadge value={trade.pnl_percent} />
            </div>
            <div className="mt-4 grid grid-cols-2 gap-3 text-sm">
              <div>
                <p className="text-muted-foreground">Entry</p>
                <p className="mt-1 text-foreground">{formatCurrency(trade.entry_price)}</p>
              </div>
              <div>
                <p className="text-muted-foreground">Exit</p>
                <p className="mt-1 text-foreground">{formatCurrency(trade.exit_price)}</p>
              </div>
              <div>
                <p className="text-muted-foreground">R multiple</p>
                <p className="mt-1 text-foreground">{formatSignedNumber(trade.r_multiple)}</p>
              </div>
              <div>
                <p className="text-muted-foreground">Closed</p>
                <p className="mt-1 text-foreground">{formatDate(trade.closed_at)}</p>
              </div>
            </div>
            <p className="mt-4 text-sm leading-6 text-muted-foreground">
              {truncateText(trade.notes, 140)}
            </p>
          </div>
        ))}
      </div>
      <div className="hidden overflow-hidden rounded-3xl border border-white/10 md:block">
        <table className="min-w-full divide-y divide-white/10">
          <thead className="bg-white/5">
            <tr className="text-left text-xs uppercase tracking-[0.22em] text-muted-foreground">
              <th className="px-4 py-4">Ticker</th>
              <th className="px-4 py-4">Direction</th>
              <th className="px-4 py-4">Entry</th>
              <th className="px-4 py-4">Exit</th>
              <th className="px-4 py-4">Stop</th>
              <th className="px-4 py-4">Result %</th>
              <th className="px-4 py-4">R Multiple</th>
              <th className="px-4 py-4">Outcome</th>
              <th className="px-4 py-4">Opened</th>
              <th className="px-4 py-4">Closed</th>
              <th className="px-4 py-4">Source</th>
              <th className="px-4 py-4">Notes</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-white/10 bg-white/[0.03] text-sm">
            {visibleTrades.map((trade) => (
              <tr className="align-top" key={trade.id}>
                <td className="px-4 py-4 font-semibold text-foreground">{trade.ticker}</td>
                <td className="px-4 py-4">
                  <DirectionBadge direction={trade.direction} />
                </td>
                <td className="px-4 py-4 text-foreground">{formatCurrency(trade.entry_price)}</td>
                <td className="px-4 py-4 text-foreground">{formatCurrency(trade.exit_price)}</td>
                <td className="px-4 py-4 text-muted-foreground">{formatCurrency(trade.stop_price)}</td>
                <td className="px-4 py-4">
                  <ResultBadge value={trade.pnl_percent} />
                </td>
                <td className="px-4 py-4 text-foreground">{formatSignedNumber(trade.r_multiple)}</td>
                <td className="px-4 py-4 text-muted-foreground">{trade.outcome_label ?? "N/A"}</td>
                <td className="px-4 py-4 text-muted-foreground">{formatDate(trade.opened_at)}</td>
                <td className="px-4 py-4 text-muted-foreground">{formatDate(trade.closed_at)}</td>
                <td className="px-4 py-4 text-muted-foreground">{trade.source_label ?? "N/A"}</td>
                <td className="max-w-xs px-4 py-4 text-muted-foreground">
                  {truncateText(trade.notes, compact ? 80 : 160)}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </>
  );
}
