import Link from "next/link";

import { Button, buttonStyles } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select } from "@/components/ui/select";

export function TradeFilters({
  action,
  ticker,
  direction,
}: {
  action: string;
  ticker?: string;
  direction?: string;
}) {
  return (
    <form action={action} className="grid gap-3 md:grid-cols-[minmax(0,1fr)_220px_auto_auto]">
      <Input defaultValue={ticker} name="ticker" placeholder="Filter by ticker" />
      <Select defaultValue={direction ?? "all"} name="direction">
        <option value="all">All directions</option>
        <option value="long">Long</option>
        <option value="short">Short</option>
      </Select>
      <Button type="submit" variant="secondary">
        Apply filters
      </Button>
      <Link className={buttonStyles({ variant: "ghost", size: "md" })} href={action}>
        Reset
      </Link>
    </form>
  );
}
