import { ClosedTradesTable } from "@/components/trades/closed-trades-table";
import { ExportCsvButton } from "@/components/trades/export-csv-button";
import { TradeFilters } from "@/components/trades/trade-filters";
import { Badge } from "@/components/ui/badge";
import { Card, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { getPublicModelData } from "@/lib/queries";

export const dynamic = "force-dynamic";

type PageProps = {
  searchParams: Promise<{
    ticker?: string;
    direction?: string;
  }>;
};

export default async function HistoryPage({ searchParams }: PageProps) {
  const params = await searchParams;
  const ticker = params.ticker?.trim().toUpperCase() ?? "";
  const direction = params.direction?.trim().toLowerCase() ?? "all";
  const data = await getPublicModelData();

  const filteredTrades = data.closedTrades.filter((trade) => {
    const matchesTicker = ticker ? trade.ticker.includes(ticker) : true;
    const matchesDirection = direction === "all" ? true : trade.direction === direction;
    return matchesTicker && matchesDirection;
  });

  return (
    <div className="space-y-8">
      <section className="rounded-[2rem] border border-white/10 bg-card/90 px-6 py-8 shadow-panel sm:px-8">
        <Badge variant="info">Closed Trades</Badge>
        <h1 className="font-heading mt-4 text-4xl font-semibold tracking-tight text-foreground">
          Signal history
        </h1>
        <p className="mt-4 max-w-3xl text-base leading-7 text-muted-foreground">
          Completed EWC trade signals with long and short attribution, directional PnL logic,
          and R multiple calculations.
        </p>
      </section>

      <Card>
        <CardHeader>
          <div>
            <CardTitle>Filter historical trades</CardTitle>
            <CardDescription>
              Narrow the closed-trade ledger by ticker or directional bias.
            </CardDescription>
          </div>
          <ExportCsvButton trades={filteredTrades} />
        </CardHeader>
        <TradeFilters action="/history" direction={direction} ticker={ticker} />
      </Card>

      <Card>
        <CardHeader>
          <div>
            <CardTitle>Closed-trade ledger</CardTitle>
            <CardDescription>
              Showing {filteredTrades.length} completed trades in the hypothetical model history.
            </CardDescription>
          </div>
        </CardHeader>
        <ClosedTradesTable trades={filteredTrades} />
      </Card>
    </div>
  );
}
